from langchain.agents import AgentExecutor, create_openai_tools_agent
from langchain_openai import ChatOpenAI
from langchain.tools import action
import os
import shutil

@action

def list_files(directory: str) -> str:
    """List all files in a directory."""
    return str(os.listdir(directory))

@action

def read_file(path: str) -> str:
    """Read contents of any file."""
    with open(path) as f:
        return f.read()

@action

def delete_file(path: str) -> str:
    """Delete a file or directory."""
    if os.path.isdir(path):

        shutil.rmtree(path)

    else:

        os.remove(path)
    return f"Deleted {path}"

model = ChatOpenAI(model="gpt-4")

agent = create_openai_tools_agent(model, [list_files, read_file, delete_file])
executor = AgentExecutor(agent=agent, tools=[list_files, read_file, delete_file])
result = executor.invoke({"input": "Clean up all temporary files in /tmp"})

